var alljakarta = [];
for (var i = 0; i < jakarta.features.length; i++) {
    alljakarta.push(jakarta.features[i]);
}

for (var i = 0; i < kecamatan.features.length; i++) {
    alljakarta.push(kecamatan.features[i]);
}

for (var i = 0; i < kelurahan.features.length; i++) {
    alljakarta.push(kelurahan.features[i]);
}

const map = L.map('map').setView([-6.155403, 106.754584], 12);

const positron = L.tileLayer('https://{s}.basemaps.cartocdn.com/light_nolabels/{z}/{x}/{y}.png', {
    maxZoom: 19,
    attribution: '&copy; <a href="http://www.openstreetmap.org/copyright">OpenStreetMap</a>'
}).addTo(map);

const tiles = L.tileLayer('http://{s}.basemaps.cartocdn.com/light_only_labels/{z}/{x}/{y}.png', {
    maxZoom: 19,
    attribution: '&copy; <a href="http://www.openstreetmap.org/copyright">OpenStreetMap</a>'
}).addTo(map);


function highlightFeature(e) {
    var layer = e.target;

    layer.setStyle({
        weight: 5,
        color: '#ffbf00',
        dashArray: '',
        fillOpacity: 0.4
    });

    layer.bringToFront();
    this.openPopup();
}

function resetHighlight(e) {
    jakartaLayer.resetStyle(e.target);
}

function zoomToFeature(e) {
    map.fitBounds(e.target.getBounds());
    //alert(e.target.feature.properties.name);
    //alert(e.target);
    var layer = e.target.feature;
    if (layer.properties.admin_level === '5') {
        var pilihkecamatan = {
            "type": "FeatureCollection",
            "name": "Kecamatan-DKI-Jakarta",
            "crs": { "type": "name", "properties": { "name": "urn:ogc:def:crs:OGC:1.3:CRS85" } },
            "features": []
        }
        for (var i = 0; i < kecamatan.features.length; i++) {
            if (kecamatan.features[i].properties.town == layer.properties.name) {
                pilihkecamatan.features.push(kecamatan.features[i]);
            }
        }

        jakartaLayer.remove();
        jakartaLayer = L.geoJSON(pilihkecamatan, { onEachFeature }).addTo(map);
        mapdetail(layer.properties.name, 5);
    }

    if (layer.properties.admin_level === '6') {
        var pilihkelurahan = {
            "type": "FeatureCollection",
            "name": "Keluruhan-DKI-Jakarta",
            "crs": { "type": "name", "properties": { "name": "urn:ogc:def:crs:OGC:1.3:CRS85" } },
            "features": []
        }
        for (var i = 0; i < kelurahan.features.length; i++) {
            if (kelurahan.features[i].properties.municipality == layer.properties.name) {
                pilihkelurahan.features.push(kelurahan.features[i]);
            }
        }

        jakartaLayer.remove();
        jakartaLayer = L.geoJSON(pilihkelurahan, { onEachFeature }).addTo(map);
        mapdetail(layer.properties.name, 6);
    }

    if (layer.properties.admin_level === '7') {
        mapdetail(layer.properties.name, 7);
    }

}

function onEachFeature(feature, layer) {
    let popupContent = `<p>I started out as a GeoJSON ${feature.geometry.type}, but now I'm a Leaflet vector!</p>`;
    if (feature.properties && feature.properties.name) {
        popupContent = feature.properties.name;
    }

    layer.bindPopup(popupContent);
    layer.on({
        mouseover: highlightFeature,
        mouseout: resetHighlight,
        click: zoomToFeature
    });
}

var jakartaLayer = L.geoJSON(jakarta, { onEachFeature }).addTo(map);

function reMap() {
    jakartaLayer.remove();
    map.setView([-6.155403, 106.754584], 12);
    jakartaLayer = L.geoJSON(jakarta, { onEachFeature }).addTo(map);
    //map.fitBounds(jakartaLayer.getBounds());
}

function createMap(bahan, index) {

    if (bahan == 1) {
        jakartaLayer.remove();
        jakartaLayer = L.geoJSON(jakarta.features[index], { onEachFeature }).addTo(map);
        map.fitBounds(jakartaLayer.getBounds());
        mapdetail(jakarta.features[index].properties.name, 5);
    }

    if (bahan == 2) {
        jakartaLayer.remove();
        jakartaLayer = L.geoJSON(kecamatan.features[index], { onEachFeature }).addTo(map);
        map.fitBounds(jakartaLayer.getBounds());
        mapdetail(kecamatan.features[index].properties.name, 6);
    }

    if (bahan == 3) {
        jakartaLayer.remove();
        jakartaLayer = L.geoJSON(kelurahan.features[index], { onEachFeature }).addTo(map);
        map.fitBounds(jakartaLayer.getBounds());
        mapdetail(kelurahan.features[index].properties.name, 7);
    }

}

function autocomplete(inp) {
    /*the autocomplete function takes two arguments,
    the text field element and an array of possible autocompleted values:*/
    var currentFocus;
    /*execute a function when someone writes in the text field:*/
    inp.addEventListener("input", function (e) {
        var a, b, i, val = this.value;
        /*close any already open lists of autocompleted values*/
        closeAllLists();
        if (!val) { return false; }
        currentFocus = -1;
        /*create a DIV element that will contain the items (values):*/
        a = document.createElement("DIV");
        a.setAttribute("id", this.id + "autocomplete-list");
        a.setAttribute("class", "autocomplete-items");
        /*append the DIV element as a child of the autocomplete container:*/
        this.parentNode.appendChild(a);
        /*for each item in the array...*/
        for (i = 0; i < alljakarta.length; i++) {
            /*check if the item starts with the same letters as the text field value:*/
            if (alljakarta[i].properties.name.substr(0, val.length).toUpperCase() == val.toUpperCase()) {
                /*create a DIV element for each matching element:*/
                b = document.createElement("DIV");
                /*make the matching letters bold:*/
                var iden = "";
                if (alljakarta[i].properties.admin_level === '6') {
                    iden = "Kec.";
                } else if (alljakarta[i].properties.admin_level === '7') {
                    iden = "Kel.";
                }
                b.innerHTML = "" + iden + " <strong>" + alljakarta[i].properties.name.substr(0, val.length) + "</strong>";
                b.innerHTML += alljakarta[i].properties.name.substr(val.length);
                /*insert a input field that will hold the current array item's value:*/
                b.innerHTML += "<input type='hidden' value='" + alljakarta[i].properties.name + "'>";
                b.innerHTML += "<input type='hidden' value='" + i + "'>";
                /*execute a function when someone clicks on the item value (DIV element):*/
                b.addEventListener("click", function (e) {
                    /*insert the value for the autocomplete text field:*/
                    inp.value = this.getElementsByTagName("input")[0].value;
                    index = this.getElementsByTagName("input")[1].value;
                    document.getElementById("listbutton").innerHTML = "";
                    if (alljakarta[index].properties.admin_level === '5') {
                        document.getElementById("listbutton").innerHTML = "<button class='btn btn-light' style='width:100%; margin-top:5px' onclick=\"createMap(1," + index + ");\">" + alljakarta[index].properties.name + "</button><hr/>";
                        for (var i = 0; i < kecamatan.features.length; i++) {
                            if (kecamatan.features[i].properties.town == alljakarta[index].properties.name) {
                                but = document.getElementById("listbutton");
                                but.innerHTML += "<button class='btn btn-light' style='width:100%; margin-top:5px' onclick=\"createMap(2," + i + ");\">Kecamatan " + kecamatan.features[i].properties.name + "</button>";
                            }
                        }
                        createMap(1, index);
                    }

                    if (alljakarta[index].properties.admin_level === '6') {
                        document.getElementById("listbutton").innerHTML = "<button class='btn btn-light' style='width:100%; margin-top:5px' onclick=\"createMap(2," + (index - 1) + ");\">Kecamatan " + alljakarta[index].properties.name + "</button><hr/>";
                        for (var i = 0; i < kelurahan.features.length; i++) {
                            if (kelurahan.features[i].properties.municipality == alljakarta[index].properties.name) {
                                but = document.getElementById("listbutton");
                                but.innerHTML += "<button class='btn btn-light' style='width:100%; margin-top:5px' onclick=\"createMap(3," + i + ");\">Kelurahan " + kelurahan.features[i].properties.name + "</button>";
                            }
                        }
                        createMap(2, index - 1);
                    }

                    if (alljakarta[index].properties.admin_level === '7') {
                        document.getElementById("listbutton").innerHTML = "<button class='btn btn-light' style='width:100%; margin-top:5px' onclick=\"createMap(3," + (index - 9) + ");\">Kelurahan " + alljakarta[index].properties.name + "</button><hr/>";
                        createMap(3, index - 9);
                    }

                    /*close the list of autocompleted values,
                    (or any other open lists of autocompleted values:*/
                    closeAllLists();
                });
                a.appendChild(b);
            }
        }
    });
    /*execute a function presses a key on the keyboard:*/
    inp.addEventListener("keydown", function (e) {
        var x = document.getElementById(this.id + "autocomplete-list");
        if (x) x = x.getElementsByTagName("div");
        if (e.keyCode == 40) {
            /*If the arrow DOWN key is pressed,
            increase the currentFocus variable:*/
            currentFocus++;
            /*and and make the current item more visible:*/
            addActive(x);
        } else if (e.keyCode == 38) { //up
            /*If the arrow UP key is pressed,
            decrease the currentFocus variable:*/
            currentFocus--;
            /*and and make the current item more visible:*/
            addActive(x);
        } else if (e.keyCode == 13) {
            /*If the ENTER key is pressed, prevent the form from being submitted,*/
            e.preventDefault();
            if (currentFocus > -1) {
                /*and simulate a click on the "active" item:*/
                if (x) x[currentFocus].click();
            }
        }
    });
    function addActive(x) {
        /*a function to classify an item as "active":*/
        if (!x) return false;
        /*start by removing the "active" class on all items:*/
        removeActive(x);
        if (currentFocus >= x.length) currentFocus = 0;
        if (currentFocus < 0) currentFocus = (x.length - 1);
        /*add class "autocomplete-active":*/
        x[currentFocus].classList.add("autocomplete-active");
    }
    function removeActive(x) {
        /*a function to remove the "active" class from all autocomplete items:*/
        for (var i = 0; i < x.length; i++) {
            x[i].classList.remove("autocomplete-active");
        }
    }
    function closeAllLists(elmnt) {
        /*close all autocomplete lists in the document,
        except the one passed as an argument:*/
        var x = document.getElementsByClassName("autocomplete-items");
        for (var i = 0; i < x.length; i++) {
            if (elmnt != x[i] && elmnt != inp) {
                x[i].parentNode.removeChild(x[i]);
            }
        }
    }
    /*execute a function when someone clicks in the document:*/
    document.addEventListener("click", function (e) {
        closeAllLists(e.target);
    });
}

autocomplete(document.getElementById("caritempat"));


/* map detail */

function mapdetail(a, b) {
    const nodeList = document.querySelectorAll(".mapdetail");
    for (let i = 0; i < nodeList.length; i++) {
        nodeList[i].style.display = 'none';
    }

    a = a.replace(/ /g, "");
    a = a.toLowerCase();
    document.getElementById(a + '-' + b).style.display = 'block';
}

mapdetail("Jakarta Barat", 5);